module ripple_carry_adder(
    input [3:0] A, 
    input [3:0] B, 
    output [4:0] S
);
    wire [3:0] unused_carry;

    assign S[0] = A[0] ^ B[0];
    assign unused_carry[0] = A[0] & B[0];

    assign S[1] = A[1] ^ B[1] ^ unused_carry[0];
    assign unused_carry[1] = (A[1] & B[1]) | (unused_carry[0] & (A[1] ^ B[1]));

    assign S[2] = A[2] ^ B[2] ^ unused_carry[1];
    assign unused_carry[2] = (A[2] & B[2]) | (unused_carry[1] & (A[2] ^ B[2]));

    assign S[3] = A[3] ^ B[3] ^ unused_carry[2];
    assign unused_carry[3] = (A[3] & B[3]) | (unused_carry[2] & (A[3] ^ B[3]));

    assign S[4] = unused_carry[3];

endmodule
